import{_ as s,c as t,e as d,o as p}from"./index-3avJzaEo.js";const l={class:"container"},n={__name:"Projects",setup(e){return(i,a)=>(p(),t("div",l,[...a[0]||(a[0]=[d('<h2 class="section-title" data-v-132d7776>项目经历</h2><div class="space-y-6" data-v-132d7776><div class="card project-card" data-v-132d7776><h3 class="text-xl font-semibold mb-3 text-gray-800" data-v-132d7776>鸿蒙+SpringBoot+Vue3多端健康医疗系统</h3><p class="text-gray-500 mb-4" data-v-132d7776>https://github.com/luojiang001/Pulse</p><p class="text-gray-500 mb-4" data-v-132d7776>2026/02</p><div class="flex flex-wrap gap-2 mb-4" data-v-132d7776><span class="tag" data-v-132d7776>Java</span><span class="tag" data-v-132d7776>SpringBoot 3.x</span><span class="tag" data-v-132d7776>MyBatisPlus</span><span class="tag" data-v-132d7776>Redis</span><span class="tag" data-v-132d7776>RabbitMQ</span><span class="tag" data-v-132d7776>ElasticSearch</span><span class="tag" data-v-132d7776>Vue3</span><span class="tag" data-v-132d7776>TypeScript</span><span class="tag" data-v-132d7776>HarmonyOS NEXT</span><span class="tag" data-v-132d7776>ArkTS</span><span class="tag" data-v-132d7776>MySQL</span></div><div class="mb-4" data-v-132d7776><h4 class="font-medium mb-2 text-gray-700" data-v-132d7776>项目介绍</h4><p class="text-gray-600" data-v-132d7776> 基于前后端分离架构开发的多端适配智慧医疗系统实现在线挂号、AI智能问诊、医患沟通、药品购买、电子处方、科室/医生管理等核心功能，支持Web端+鸿蒙移动端双端使用 </p></div><div class="mb-4" data-v-132d7776><h4 class="font-medium mb-2 text-gray-700" data-v-132d7776>项目内容</h4><ul class="space-y-2 text-gray-600" data-v-132d7776><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>①</span><span data-v-132d7776>后端基于SpringBoot+MyBatisPlus搭建分层架构，设计JWT身份认证，实现权限控制与敏感数据加密；</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>②</span><span data-v-132d7776>整合Redis缓存热点数据、RabbitMQ处理异步消息、ElasticSearch实现医疗信息检索，优化系统性能；</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>③</span><span data-v-132d7776>基于Docker完成后端服务、MySQL、Redis等组件的容器化部署通过Nginx配置反向代理实现前端静态资源部署与接口转发，优化访问性能。</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>④</span><span data-v-132d7776>集成SpringAI框架对接通义千问大模型，开发AI智能问诊模块</span></li></ul></div><div data-v-132d7776><h4 class="font-medium mb-2 text-gray-700" data-v-132d7776>项目难点与解决</h4><ul class="space-y-2 text-gray-600" data-v-132d7776><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>•</span><span data-v-132d7776>解决多中间件协同的数据一致性问题，设计缓存懒加载+过期策略、MQ消息确认机制，实现ES与数据库数据同步，将接口平均响应时间从3.5秒优化至1.1秒，并发承载能力提升至800 QPS；</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>•</span><span data-v-132d7776>AI智能问诊模块开发：通过指令式提示、少样本学习、思维链推理等Prompt工程技术，将通义千问大模型定制为专业医疗问诊助手；对用户输入进行结构化清洗，对模型输出进行JSON格式后处理，使科室推荐准确率达85%，单轮响应时间控制在1.2秒内，并发承载能力提升至500 QPS</span></li></ul></div></div><br data-v-132d7776><br data-v-132d7776><div class="card project-card" data-v-132d7776><h3 class="text-xl font-semibold mb-3 text-gray-800" data-v-132d7776>智能项目管理平台</h3><p class="text-gray-500 mb-4" data-v-132d7776>2026/02-2026/03</p><div class="flex flex-wrap gap-2 mb-4" data-v-132d7776><span class="tag" data-v-132d7776>Java</span><span class="tag" data-v-132d7776>SpringBoot</span><span class="tag" data-v-132d7776>SpringCloud</span><span class="tag" data-v-132d7776>Nacos</span><span class="tag" data-v-132d7776>Sentinel</span><span class="tag" data-v-132d7776>MyBatis</span><span class="tag" data-v-132d7776>MySQL</span><span class="tag" data-v-132d7776>Redis</span><span class="tag" data-v-132d7776>RabbitMQ</span><span class="tag" data-v-132d7776>ElasticSearch</span><span class="tag" data-v-132d7776>Vue3</span><span class="tag" data-v-132d7776>TypeScript</span></div><div class="mb-4" data-v-132d7776><h4 class="font-medium mb-2 text-gray-700" data-v-132d7776>项目介绍</h4><p class="text-gray-600" data-v-132d7776> 基于SpringCloud Alibaba微服务架构的智能项目管理平台，通过项目创建、任务指派、自定义流程、灵活的角色权限管理等核心功能，提升企业项目管理效率，实现项目全生命周期的流程化、智能化管控。 </p></div><div class="mb-4" data-v-132d7776><h4 class="font-medium mb-2 text-gray-700" data-v-132d7776>核心内容</h4><ul class="space-y-2 text-gray-600" data-v-132d7776><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>①</span><span data-v-132d7776>自定义Gateway全局过滤器，实现SpringCloud微服务网关统一鉴权(比如JWT令牌校验、登录状态校验等），并统计接口调用耗时情况，以便接口影响出现异常时能够快速进行定位</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>②</span><span data-v-132d7776>基于TransmittableThreadLocal (TTL)自定义请求头拦截器，将Header 数据封装到线程变量中方便获取，减少用户信息数据库查询次数，同时验证当前用户有效期自动刷新有效期。</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>③</span><span data-v-132d7776>使用Redission分布式锁来确保流程状态的更新按顺序执行，且不被其他流程服务操作干扰。</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>④</span><span data-v-132d7776>使用OpenFeign与 Sentinel构建自定义Fallback 服务降级方案，确保系统在服务异常时仍提供核心功能;同时利用Gateway结合Sentinel实施网关层面的流量控制，有效削峰填谷，防止单点服务过载，保障可用性。</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>④</span><span data-v-132d7776>采用Seata分布式事务框架的AT模式，有效解决了微服务架构下的数据一致性挑战。</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>④</span><span data-v-132d7776>设计并开发基于自定义注解与AOP的服务接口鉴权与内部认证体系，实现了细粒度的权限控制。</span></li><li class="flex items-start gap-2" data-v-132d7776><span class="text-primary" data-v-132d7776>④</span><span data-v-132d7776>利用RocketMQ对项目和任务审批流消息进行异步解裁，project服务发起审批，workfiow服务监听到后推送到 MQ的生产者，消费者进行幂等校验后发起企业微信通知。</span></li></ul></div></div></div>',2)])]))}},v=s(n,[["__scopeId","data-v-132d7776"]]);export{v as default};
